import { useEffect, useMemo, useState } from "react";
import {
  Container,
  Card,
  Button,
  Alert,
  Form,
  Spinner,
  Table,
  Badge,
  Row,
  Col,
} from "react-bootstrap";
import { useNavigate, useParams } from "react-router-dom";
import { getOrderDetail } from "../services/orderService";
import { payOrder } from "../services/paymentService";

function PaymentPage() {
  const { orderId } = useParams();
  const navigate = useNavigate();

  const [order, setOrder] = useState(null);
  const [items, setItems] = useState([]);
  const [payments, setPayments] = useState([]);
  const [paymentMethod, setPaymentMethod] = useState("demo");
  const [walletAddress, setWalletAddress] = useState("");
  const [blockchainTxHash, setBlockchainTxHash] = useState("");
  const [gatewayTransactionId, setGatewayTransactionId] = useState("");
  const [loading, setLoading] = useState(true);
  const [paying, setPaying] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const loadOrder = async () => {
    const response = await getOrderDetail(orderId);

    if (response.data?.success) {
      const payload = response.data.data;
      setOrder(payload);
      setItems(Array.isArray(payload.items) ? payload.items : []);
      setPayments(Array.isArray(payload.payments) ? payload.payments : []);

      if (payload.payment_status === "paid" && payload.order_status === "processing") {
        setSuccess("Thanh toán thành công. Đơn hàng đang được hệ thống xử lý.");
      }
    } else {
      setError("Không lấy được thông tin đơn hàng");
    }
  };

  useEffect(() => {
    const fetchOrder = async () => {
      try {
        setLoading(true);
        setError("");
        setSuccess("");
        await loadOrder();
      } catch (err) {
        setError(err.response?.data?.message || "Lỗi khi tải đơn hàng");
      } finally {
        setLoading(false);
      }
    };

    fetchOrder();
  }, [orderId]);

  const isPaid = order?.payment_status === "paid";
  const isExpired = order?.payment_status === "expired" || order?.order_status === "expired";
  const requiresBlockchainFields = paymentMethod === "metamask";

  const latestPayment = useMemo(() => {
    if (!payments.length) return null;
    return payments[0];
  }, [payments]);

  const handleProcessPayment = async () => {
    try {
      if (!order) return;

      setPaying(true);
      setError("");
      setSuccess("");

      if (requiresBlockchainFields) {
        if (!walletAddress.trim()) {
          setError("Vui lòng nhập địa chỉ ví thanh toán.");
          setPaying(false);
          return;
        }

        if (!blockchainTxHash.trim()) {
          setError("Vui lòng nhập blockchain tx hash khi chọn Metamask.");
          setPaying(false);
          return;
        }
      }

      const response = await payOrder({
        order_id: Number(order.id),
        amount: Number(order.total_amount),
        payment_method: paymentMethod,
        currency: "VND",
        gateway_transaction_id: gatewayTransactionId.trim(),
        blockchain_tx_hash: blockchainTxHash.trim(),
        payer_wallet_address: walletAddress.trim(),
        gateway_response: {
          source: "frontend-demo",
          submitted_at: new Date().toISOString(),
        },
      });

      if (response.data?.success) {
        setSuccess("Thanh toán thành công. Đơn hàng đang được xử lý để phát hành vé.");
        await loadOrder();
      } else {
        setError(response.data?.message || "Không thể thanh toán đơn hàng");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Lỗi khi xử lý thanh toán");
    } finally {
      setPaying(false);
    }
  };

  const getPaymentBadge = (status) => {
    switch (status) {
      case "paid":
        return "success";
      case "failed":
        return "danger";
      case "expired":
        return "secondary";
      case "refunded":
        return "dark";
      default:
        return "warning";
    }
  };

  const getOrderBadge = (status) => {
    switch (status) {
      case "awaiting_payment":
        return "warning";
      case "processing":
        return "info";
      case "completed":
        return "success";
      case "cancelled":
        return "secondary";
      case "expired":
        return "dark";
      default:
        return "warning";
    }
  };

  const renderPaymentText = (status) => {
    switch (status) {
      case "pending":
        return "Chờ thanh toán";
      case "paid":
        return "Đã thanh toán";
      case "failed":
        return "Thất bại";
      case "expired":
        return "Hết hạn";
      case "refunded":
        return "Đã hoàn tiền";
      default:
        return status || "Không xác định";
    }
  };

  const renderOrderText = (status) => {
    switch (status) {
      case "awaiting_payment":
        return "Chờ thanh toán";
      case "processing":
        return "Đang xử lý";
      case "completed":
        return "Hoàn tất";
      case "cancelled":
        return "Đã hủy";
      case "expired":
        return "Hết hạn";
      default:
        return status || "Không xác định";
    }
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ minHeight: "70vh" }}>
        <Spinner animation="border" />
      </div>
    );
  }

  if (!order) {
    return (
      <Container className="user-shell text-center">
        <h3>Không tìm thấy đơn hàng</h3>
      </Container>
    );
  }

  return (
    <Container className="user-shell">
      <Row className="g-4">
        <Col lg={8}>
          <Card className="payment-card">
            <Card.Body className="p-4 p-lg-5">
              <div className="section-title mb-2">Thanh toán đơn hàng</div>
              <div className="section-subtitle mb-4">
                Theo backend hiện tại: thanh toán xong thì đơn chuyển sang <strong>processing</strong>, chưa mint NFT ngay.
              </div>

              {error && <Alert variant="danger">{error}</Alert>}
              {success && <Alert variant="success">{success}</Alert>}
              {isExpired && (
                <Alert variant="warning">Đơn hàng này đã hết hạn thanh toán. Bạn cần tạo đơn mới.</Alert>
              )}

              <Row className="g-3 mb-4">
                <Col md={6}>
                  <div className="payment-summary-box">
                    <div className="text-muted mb-1">Mã đơn</div>
                    <div className="fw-bold fs-5">{order.order_code}</div>
                  </div>
                </Col>
                <Col md={6}>
                  <div className="payment-summary-box">
                    <div className="text-muted mb-1">Tổng tiền</div>
                    <div className="fw-bold fs-5">
                      {Number(order.total_amount).toLocaleString("vi-VN")} VND
                    </div>
                  </div>
                </Col>
              </Row>

              <div className="d-flex gap-3 flex-wrap mb-4">
                <Badge bg={getPaymentBadge(order.payment_status)} className="status-badge">
                  Thanh toán: {renderPaymentText(order.payment_status)}
                </Badge>
                <Badge bg={getOrderBadge(order.order_status)} className="status-badge">
                  Đơn hàng: {renderOrderText(order.order_status)}
                </Badge>
              </div>

              <h5 className="fw-bold mb-3">Chi tiết vé</h5>

              <Table responsive hover className="table-modern align-middle mb-4">
                <thead>
                  <tr>
                    <th>Loại vé</th>
                    <th>Số lượng</th>
                    <th>Đơn giá</th>
                    <th>Thành tiền</th>
                  </tr>
                </thead>
                <tbody>
                  {items.map((item) => (
                    <tr key={item.id}>
                      <td className="fw-semibold">{item.ticket_type_name_snapshot}</td>
                      <td>{item.quantity}</td>
                      <td>{Number(item.unit_price).toLocaleString("vi-VN")} VND</td>
                      <td>{Number(item.subtotal).toLocaleString("vi-VN")} VND</td>
                    </tr>
                  ))}
                </tbody>
              </Table>

              {!isPaid && !isExpired && (
                <>
                  <Form.Group className="mb-3">
                    <Form.Label>Phương thức thanh toán</Form.Label>
                    <Form.Select value={paymentMethod} onChange={(e) => setPaymentMethod(e.target.value)}>
                      <option value="demo">Demo</option>
                      <option value="bank_transfer">Chuyển khoản</option>
                      <option value="cash">Tiền mặt</option>
                      <option value="stripe">Stripe</option>
                      <option value="metamask">Metamask</option>
                    </Form.Select>
                  </Form.Group>

                  {requiresBlockchainFields && (
                    <>
                      <Form.Group className="mb-3">
                        <Form.Label>Địa chỉ ví thanh toán</Form.Label>
                        <Form.Control
                          type="text"
                          placeholder="Nhập địa chỉ ví dạng 0x..."
                          value={walletAddress}
                          onChange={(e) => setWalletAddress(e.target.value)}
                        />
                      </Form.Group>

                      <Form.Group className="mb-3">
                        <Form.Label>Blockchain tx hash</Form.Label>
                        <Form.Control
                          type="text"
                          placeholder="Nhập tx hash dạng 0x..."
                          value={blockchainTxHash}
                          onChange={(e) => setBlockchainTxHash(e.target.value)}
                        />
                      </Form.Group>
                    </>
                  )}

                  <Form.Group className="mb-4">
                    <Form.Label>Mã giao dịch cổng thanh toán</Form.Label>
                    <Form.Control
                      type="text"
                      placeholder="Có thể để trống với chế độ demo"
                      value={gatewayTransactionId}
                      onChange={(e) => setGatewayTransactionId(e.target.value)}
                    />
                  </Form.Group>
                </>
              )}

              <div className="d-flex gap-3 flex-wrap">
                {!isPaid && !isExpired && (
                  <Button
                    className="soft-button soft-button-primary"
                    onClick={handleProcessPayment}
                    disabled={paying}
                  >
                    {paying ? "Đang xử lý..." : "Thanh toán ngay"}
                  </Button>
                )}

                <Button className="soft-button soft-button-dark" onClick={() => navigate("/profile")}>
                  Về hồ sơ
                </Button>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col lg={4}>
          <Card className="payment-card mb-4">
            <Card.Body className="p-4">
              <div className="section-title mb-3" style={{ fontSize: "1.4rem" }}>
                Tiến trình
              </div>

              <div className="d-flex flex-column gap-3">
                <div className="payment-summary-box">
                  <div className="fw-bold">1. Tạo đơn hàng</div>
                  <div className="text-muted">Đã hoàn tất</div>
                </div>

                <div className="payment-summary-box">
                  <div className="fw-bold">2. Thanh toán</div>
                  <div className="text-muted">{isPaid ? "Đã hoàn tất" : "Chưa hoàn tất"}</div>
                </div>

                <div className="payment-summary-box">
                  <div className="fw-bold">3. Xử lý đơn</div>
                  <div className="text-muted">
                    {order.order_status === "processing"
                      ? "Đơn đang được xử lý"
                      : order.order_status === "completed"
                      ? "Đã hoàn tất"
                      : "Chờ xử lý"}
                  </div>
                </div>

                <div className="payment-summary-box">
                  <div className="fw-bold">4. Issue/Mint vé</div>
                  <div className="text-muted">Luồng này do admin/backend xử lý sau.</div>
                </div>
              </div>
            </Card.Body>
          </Card>

          <Card className="payment-card">
            <Card.Body className="p-4">
              <div className="section-title mb-3" style={{ fontSize: "1.4rem" }}>
                Lần thanh toán gần nhất
              </div>

              {latestPayment ? (
                <div className="payment-summary-box">
                  <div className="mb-2">
                    <strong>Mã thanh toán:</strong> {latestPayment.payment_code}
                  </div>
                  <div className="mb-2">
                    <strong>Phương thức:</strong> {latestPayment.payment_method}
                  </div>
                  <div className="mb-2">
                    <strong>Số tiền:</strong> {Number(latestPayment.amount).toLocaleString("vi-VN")} {latestPayment.currency}
                  </div>
                  <div className="mb-2">
                    <strong>Trạng thái:</strong> {latestPayment.status}
                  </div>
                  <div>
                    <strong>Thời gian:</strong>{" "}
                    {latestPayment.paid_at
                      ? new Date(latestPayment.paid_at).toLocaleString("vi-VN")
                      : "Chưa thanh toán"}
                  </div>
                </div>
              ) : (
                <div className="text-muted">Chưa có bản ghi thanh toán nào.</div>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default PaymentPage;
